export function log(msg: string): void {
  console.log(`[foo] ${msg}`);
}

export function log(msg: string): void {
  console.log(`[bar] ${msg}`);
}

export function log(msg: string): void {
  console.log(`[baz] ${msg}`);
}

import { log } from "./foo";
import { describe, it, spyOn, expect } from "bun:test";

describe("foo.log", () => {
  it("should prefix with [foo]", () => {
    const spy = spyOn(console, "log");
    log("hello");
    expect(spy).toHaveBeenCalledWith("[foo] hello");
  });
});

